import React, { useRef, useState } from "react";

export default function Header() {
  return (
    <>
      <header
        style={{
          background: "#5D5FEF",
          color: "#fff",
          padding: "1.25rem 2rem",
          borderRadius: "0 0 24px 24px",
          boxShadow: "0 2px 8px #7286D333",
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <div>
            <div style={{ fontSize: 16, fontWeight: 500 }}>9:41</div>
            <div style={{ fontSize: 16, marginTop: 4 }}>Hello Monica!</div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>Welcome back</div>
          </div>
          <div>
            <button
              style={{
                border: "none",
                background: "#fff",
                color: "#5D5FEF",
                borderRadius: 12,
                padding: "8px 24px",
                fontWeight: 500,
                fontSize: 16,
                boxShadow: "0 2px 8px #7286D311",
              }}
            >
              Notifications
            </button>
          </div>
        </div>
      </header>
    </>
  );
}
